import{_ as t,C as r,o as s,c as o,a4 as n,E as l}from"./chunks/framework.BIaKE42g.js";const g=JSON.parse('{"title":"Starfield, plasma & fire","description":"A full-screen truecolor effects canvas — flying starfield, plasma, and fire — a runnable JSVision example in the browser.","frontmatter":{"title":"Starfield, plasma & fire","description":"A full-screen truecolor effects canvas — flying starfield, plasma, and fire — a runnable JSVision example in the browser."},"headers":[],"relativePath":"apps/effects.md","filePath":"apps/effects.md"}'),i={name:"apps/effects.md"};function c(f,e,p,d,m,h){const a=r("PlayExample");return s(),o("div",null,[e[0]||(e[0]=n('<h1 id="starfield-plasma-fire" tabindex="-1">Starfield, plasma &amp; fire <a class="header-anchor" href="#starfield-plasma-fire" aria-label="Permalink to &quot;Starfield, plasma &amp; fire&quot;">​</a></h1><p>A full-screen canvas running one of three animated effects, each drawn cell by cell in truecolor: a flying <strong>starfield</strong>, a sinusoidal <strong>plasma</strong> field, and a bottom-up <strong>fire</strong>. Press <strong>1</strong>, <strong>2</strong>, or <strong>3</strong> to pick one, or <strong>Space</strong> to cycle.</p><p>There is no image and no shader here — every cell&#39;s colour is computed per frame and handed to the engine as a <code>#rrggbb</code> value, which then downsamples it to whatever the terminal actually supports (256 colours, 16, or monochrome). So this doubles as a live stress test of two things at once: the colour engine, and the damage-diff renderer that repaints only the cells that changed.</p>',3)),l(a,{id:"apps/effects",title:"Starfield, plasma & fire",blurb:"A full-screen truecolor effects canvas — flying starfield, plasma, and fire; 1/2/3 to pick, Space to cycle."})])}const _=t(i,[["render",c]]);export{g as __pageData,_ as default};
